import { GoogleGenAI, Chat } from "@google/genai";
import { Exhaust } from "../types";
import { STANDARDS, DIAGNOSTIC_SYSTEM } from "../constants";

// Initialize carefully - if offline, we still define 'ai' but API calls will be guarded
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Chat session management
let chatSession: Chat | null = null;

export const resetChatSession = () => {
  chatSession = null;
};

// --- OFFLINE EXPERT SYSTEM ---

const generateOfflineResponse = (message: string): string => {
  const lowerMsg = message.toLowerCase();

  if (lowerMsg.includes('سلام') || lowerMsg.includes('درود')) {
    return "سلام! من دستیار هوشمند اکو مانیتور هستم. در حال حاضر اتصال اینترنت برقرار نیست، اما می‌توانم در حالت آفلاین به سوالات شما در مورد استانداردها و وضعیت سیستم پاسخ دهم.";
  }

  if (lowerMsg.includes('استاندارد') || lowerMsg.includes('حد مجاز') || lowerMsg.includes('iso')) {
    return `**استانداردهای آلایندگی (ISO 14001):**\n\n` +
      Object.values(STANDARDS).map(s => `- **${s.name}**: ${s.limit} ${s.unit}`).join('\n');
  }

  if (lowerMsg.includes('co') || lowerMsg.includes('کربن')) {
    return `**مونوکسید کربن (CO):**\nحد مجاز: ${STANDARDS.CO.limit} ${STANDARDS.CO.unit}\n\nعلل افزایش: احتراق ناقص، کمبود اکسیژن، سرد بودن محفظه احتراق.\nراهکار: تنظیم نسبت هوا به سوخت، سرویس مشعل.`;
  }

  if (lowerMsg.includes('nox') || lowerMsg.includes('نیتروژن')) {
    return `**اکسیدهای نیتروژن (NOx):**\nحد مجاز: ${STANDARDS.NOx.limit} ${STANDARDS.NOx.unit}\n\nعلل افزایش: دمای بسیار بالای شعله.\nراهکار: استفاده از مشعل‌های Low-NOx، بازگردش دود (FGR)، تنظیم هوای اضافه.`;
  }

  return "من در حالت آفلاین هستم و فقط می‌توانم به سوالات پایه در مورد استانداردها و پارامترهای آلایندگی پاسخ دهم. برای تحلیل دقیق‌تر و پرسش‌های پیچیده، لطفاً به اینترنت متصل شوید.";
};

const generateOfflineAnalysis = (exhaustData: Exhaust): string => {
  const problems: string[] = [];
  const recommendations: string[] = [];
  let violationCount = 0;

  // 1. Analyze Data
  Object.entries(exhaustData.data).forEach(([key, value]) => {
    const std = STANDARDS[key];
    if (std && value > std.limit) {
      violationCount++;
      const ratio = value / std.limit;
      const severity = ratio > 1.2 ? 'veryHigh' : 'high';

      problems.push(`- **${std.name} (${key})**: مقدار فعلی ${value} ${std.unit} است که از حد مجاز (${std.limit}) فراتر رفته است.`);

      if (DIAGNOSTIC_SYSTEM[key]) {
        recommendations.push(`- **برای مشکل ${std.name}**: ${DIAGNOSTIC_SYSTEM[key][severity]}`);
      }
    }
  });

  // 2. Construct Report
  let report = `## گزارش فنی وضعیت سیستم (حالت آفلاین)\n`;
  report += `**تولید شده توسط سیستم خبره داخلی EcoMonitor**\n\n`;

  // Status
  if (violationCount === 0) {
    report += `### 1. وضعیت کلی\n🟢 **نرمال**: تمامی پارامترها در محدوده استاندارد قرار دارند. عملکرد سیستم احتراق مطلوب ارزیابی می‌شود.\n\n`;
  } else if (violationCount <= 2) {
    report += `### 1. وضعیت کلی\n⚠️ **هشدار**: سیستم در ${violationCount} پارامتر دچار انحراف از معیار است. نیاز به بازرسی فنی وجود دارد.\n\n`;
  } else {
    report += `### 1. وضعیت کلی\n🔴 **بحرانی**: انحراف شدید در پارامترهای متعدد مشاهده می‌شود. توقف و تعمیرات فوری توصیه می‌گردد.\n\n`;
  }

  // Problems
  report += `### 2. شناسایی مشکلات\n`;
  if (problems.length > 0) {
    report += problems.join('\n') + `\n\n`;
  } else {
    report += `هیچ انحرافی از استانداردهای تعریف شده مشاهده نشد.\n\n`;
  }

  // Recommendations
  report += `### 3. راهکارهای پیشنهادی\n`;
  if (recommendations.length > 0) {
    report += recommendations.join('\n') + `\n\n`;
  } else {
    report += `- پایش دوره‌ای طبق برنامه زمان‌بندی ادامه یابد.\n- کالیبراسیون سنسورها در موعد مقرر انجام شود.`;
  }

  report += `\n\n---\n*توجه: این گزارش توسط الگوریتم‌های تشخیصی داخلی تولید شده است. برای تحلیل دقیق‌تر مبتنی بر هوش مصنوعی مولد، اتصال اینترنت الزامی است.*`;

  return report;
};

// --- MAIN EXPORTS ---

export const sendChatMessage = async (message: string): Promise<string> => {
  if (!navigator.onLine) {
    // Use Offline Expert System
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve(generateOfflineResponse(message));
      }, 500); // Simulate processing delay
    });
  }

  try {
    if (!chatSession) {
      chatSession = ai.chats.create({
        model: 'gemini-3-pro-preview',
        config: {
          systemInstruction: 'You are an intelligent assistant for an industrial environmental monitoring system called EcoMonitor. You help engineers interpret emission data (CO, NOx, SO2, PM, O2), understand ISO 14001 standards, and troubleshoot boiler efficiency issues. Your responses should be technical, concise, and helpful. Use Persian (Farsi) language. Always format your response in a way that is easy to read in a chat window.',
        },
      });
    }

    const response = await chatSession.sendMessage({ message });
    return response.text || "متاسفانه پاسخی دریافت نشد.";
  } catch (error) {
    console.error("Chat Error:", error);
    // Fallback to offline logic if request fails
    return generateOfflineResponse(message);
  }
};

export const generateExhaustAnalysis = async (exhaustData: Exhaust): Promise<string> => {
  if (!navigator.onLine) {
    // Use Offline Expert System
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve(generateOfflineAnalysis(exhaustData));
      }, 1500); // Simulate analysis time
    });
  }

  const dataDescription = Object.entries(exhaustData.data).map(([pollutant, value]) => {
    const std = STANDARDS[pollutant];
    return `- ${std.name} (${pollutant}): ${value} ${std.unit} (Standard Limit: ${std.limit})`;
  }).join('\n');

  const prompt = `
    You are an expert environmental engineer and boiler system specialist. 
    Analyze the following emission data for an industrial boiler:

    Exhaust Name: ${exhaustData.name}
    Location: ${exhaustData.location}
    Last Check Date: ${exhaustData.lastCheck}

    Pollutant Data:
    ${dataDescription}

    Please provide a detailed technical report in Persian (Farsi) covering:
    1. **Overall Status**: A summary of the boiler's compliance with environmental standards.
    2. **Problem Identification**: Identify specific pollutants that exceed or approach limits and explain the potential mechanical or chemical causes (e.g., lean fuel mixture, low combustion temperature, sulfur content).
    3. **Actionable Recommendations**: Provide specific engineering solutions to fix the issues.
    4. **Priority**: Rank the actions from Critical to Low priority.
    5. **Estimation**: Rough time and resource estimation for the fixes.

    Format the response using clean Markdown with headers and bullet points. Use professional technical Persian terminology.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "خطا در دریافت پاسخ از هوش مصنوعی. لطفاً مجدداً تلاش کنید.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    // Fallback to offline logic if request fails
    return generateOfflineAnalysis(exhaustData);
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, RefreshCw, MessageSquare, Sparkles, WifiOff, HardDrive } from 'lucide-react';
import { useSettings } from '../contexts/SettingsContext';
import { sendChatMessage, resetChatSession } from '../services/geminiService';

interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: string;
}

interface ChatBotProps {
  isOnline: boolean;
}

export const ChatBot: React.FC<ChatBotProps> = ({ isOnline }) => {
  const { t, themeColors, dir } = useSettings();
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      text: t('chat.welcome'),
      timestamp: new Date().toLocaleTimeString()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date().toLocaleTimeString()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await sendChatMessage(userMsg.text);
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: new Date().toLocaleTimeString()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleReset = () => {
    resetChatSession();
    setMessages([{
      id: Date.now().toString(),
      role: 'model',
      text: t('chat.welcome'),
      timestamp: new Date().toLocaleTimeString()
    }]);
  };

  return (
    <div className="animate-in slide-in-from-bottom-5 duration-500 h-[calc(100vh-250px)] min-h-[500px] flex flex-col">
      <div className="bg-white dark:bg-slate-800/80 backdrop-blur-md rounded-t-2xl p-4 shadow-sm border-x border-t border-gray-200 dark:border-slate-700/50 flex justify-between items-center">
        <div className="flex items-center gap-3">
            <div className={`p-3 rounded-xl text-white shadow-lg ${isOnline ? 'bg-gradient-to-tr from-purple-500 to-indigo-500 shadow-purple-500/20' : 'bg-slate-600 shadow-slate-500/20'}`}>
                {isOnline ? <Sparkles size={24} /> : <HardDrive size={24} />}
            </div>
            <div>
                <h2 className="text-xl font-bold text-slate-800 dark:text-white">{t('nav.chat')}</h2>
                <div className="flex items-center gap-2">
                  <p className="text-xs text-slate-500 dark:text-slate-400">
                    {isOnline ? 'Gemini 3 Pro Preview' : 'EcoMonitor Offline Assistant'}
                  </p>
                  {!isOnline && (
                    <span className="text-xs bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400 px-2 py-0.5 rounded-full flex items-center gap-1">
                      <WifiOff size={10} />
                      {t('status.offline')}
                    </span>
                  )}
                </div>
            </div>
        </div>
        <button 
            onClick={handleReset}
            className="p-2 text-slate-500 hover:text-slate-800 dark:text-slate-400 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-white/10 rounded-lg transition-all tooltip"
            title={t('chat.clear')}
        >
            <RefreshCw size={20} />
        </button>
      </div>

      <div className="flex-1 bg-white/50 dark:bg-slate-900/50 backdrop-blur-sm border-x border-gray-200 dark:border-slate-700/50 overflow-y-auto p-4 space-y-4 custom-scrollbar">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-end gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div 
                className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${
                    msg.role === 'user' 
                    ? 'bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300' 
                    : isOnline 
                      ? 'bg-gradient-to-tr from-purple-500 to-indigo-500 text-white'
                      : 'bg-slate-600 text-white'
                }`}
            >
                {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
            </div>

            <div className={`max-w-[80%] rounded-2xl p-4 shadow-sm ${
                msg.role === 'user' 
                ? 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-br-none border border-gray-200 dark:border-slate-700' 
                : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-bl-none border border-purple-100 dark:border-purple-500/20'
            }`}>
                <div className="whitespace-pre-wrap leading-relaxed text-sm md:text-base">{msg.text}</div>
                <div className="text-[10px] opacity-50 mt-2 text-right dir-ltr">{msg.timestamp}</div>
            </div>
          </div>
        ))}

        {isLoading && (
            <div className="flex items-center gap-3">
                <div className={`w-8 h-8 rounded-full text-white flex items-center justify-center shrink-0 ${isOnline ? 'bg-gradient-to-tr from-purple-500 to-indigo-500' : 'bg-slate-600'}`}>
                    <Sparkles size={16} className="animate-pulse" />
                </div>
                <div className="bg-white dark:bg-slate-800 px-4 py-3 rounded-2xl rounded-bl-none border border-purple-100 dark:border-purple-500/20">
                   <div className="flex gap-1">
                      <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></div>
                      <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></div>
                      <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></div>
                   </div>
                </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="bg-white dark:bg-slate-800/80 backdrop-blur-md rounded-b-2xl p-4 border-x border-b border-gray-200 dark:border-slate-700/50">
        <div className="relative flex items-center gap-2">
            <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder={isOnline ? t('chat.placeholder') : 'دستیار آفلاین (سوالات درباره استانداردها و CO, NOx...)'}
                rows={1}
                className="w-full bg-gray-100 dark:bg-slate-900/80 border border-gray-200 dark:border-slate-600 rounded-xl px-4 py-3 pr-12 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all resize-none overflow-hidden max-h-32"
                style={{ minHeight: '50px' }}
            />
            <button
                onClick={handleSend}
                disabled={!input.trim() || isLoading}
                className={`absolute left-2 p-2 text-white rounded-lg transition-all shadow-lg ${
                    !input.trim() || isLoading 
                    ? 'bg-gray-300 dark:bg-slate-700 cursor-not-allowed' 
                    : isOnline 
                        ? 'bg-purple-600 hover:bg-purple-500 shadow-purple-500/20'
                        : 'bg-slate-600 hover:bg-slate-500 shadow-slate-500/20'
                }`}
                style={dir === 'ltr' ? { right: '0.5rem', left: 'auto' } : {}}
            >
                {isLoading ? <RefreshCw size={20} className="animate-spin" /> : <Send size={20} className={dir === 'rtl' ? 'rotate-180' : ''} />}
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCcw } from 'lucide-react';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
}

export class ErrorBoundary extends React.Component<Props, State> {
  public state: State = {
    hasError: false,
    error: null,
    errorInfo: null
  };

  public static getDerivedStateFromError(error: Error): Partial<State> {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
    this.setState({ errorInfo });
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen bg-slate-900 text-white flex items-center justify-center p-4" dir="rtl">
          <div className="bg-slate-800 border border-red-500/50 rounded-2xl p-8 max-w-lg w-full shadow-2xl">
            <div className="flex items-center gap-4 text-red-500 mb-6">
              <AlertTriangle size={48} />
              <h1 className="text-2xl font-bold">متاسفانه خطایی رخ داده است</h1>
            </div>

            <p className="text-slate-300 mb-4">
              نرم‌افزار با یک خطای غیرمنتظره مواجه شد. لطفاً صفحه را بازنشانی کنید یا با پشتیبانی تماس بگیرید.
            </p>

            <div className="bg-slate-950 p-4 rounded-xl border border-slate-700 overflow-auto max-h-48 mb-6" dir="ltr">
              <code className="text-red-400 text-xs font-mono">
                {this.state.error && this.state.error.toString()}
              </code>
            </div>

            <button
              onClick={() => window.location.reload()}
              className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-bold transition-all flex items-center justify-center gap-2"
            >
              <RefreshCcw size={20} />
              بازنشانی صفحه
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

